SELECT Nationality, AVG(CAST(REPLACE(REPLACE(Time, ':', ''), '.', '') AS REAL)) AS Average_Time
FROM T5
GROUP BY Nationality;

SELECT Rank, Nationality, Time 
FROM T5 
WHERE Nationality LIKE '%England%' OR Nationality LIKE '%France%' OR Nationality LIKE '%Scotland%' OR Nationality LIKE '%Ireland%';

SELECT Classified, AVG(CAST(REPLACE(REPLACE(REPLACE(Average_size, 'g', ''), '(', ''), ')', '') AS REAL)) AS Average_Size
FROM T21
GROUP BY Classified;

SELECT Scientific_name, Common_name, Classified, Average_size, Conservation_status
FROM T21
WHERE Average_size IS NOT NULL;
